                if idx + 1 < len(sequence):
                    next_frame[63][sequence[idx+1]] = 3
                else:
                    # Fallback to a default or wrap around
                    next_frame[63][50] = 3
            except ValueError:
                # If the last mark isn't in our sequence, use a fallback.
                next_frame[63][50] = 3

