                                next_frame[r+dr][c+dc] = 2
                                next_frame[r+2+dr][c+dc] = 14
                        found = True
                        break
            if found: break
        next_frame[63][7] = 3

    elif action == 'ACTION3':
        # Logic for ACTION3 based on transitions
        for r in [38, 39]:
            for c in range(8, 12):
                next_frame[r][c] = 14 if frame[r][c] == 2 else 2
        next_frame[63][43] = 3

    elif action == 'ACTION4':
        # Logic for ACTION4 based on transitions and Case 3
        for r in [40, 41]:
            for c in [10, 11]: next_frame[r][c] = 2
            for c in [12, 13]: next_frame[r][c] = 14
        next_frame[63][10] = 3

